python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    cmd = data.get('tool_input',{}).get('command','')
    if 'uvicorn' in cmd and 'source .env' not in cmd:
        print(json.dumps({'systemMessage': 'Reminder: source .env first so payment keys load properly.'}))
except Exception:
    pass
"

python3 -c "
import sys, json, subprocess
try:
    data = json.load(sys.stdin)
    f = data.get('tool_input',{}).get('file_path') or data.get('tool_response',{}).get('filePath','') or ''
    if f.endswith('.py'):
        r = subprocess.run(['python3','-m','py_compile',f], capture_output=True, text=True)
        if r.returncode != 0:
            print(json.dumps({'systemMessage': 'Syntax error in ' + f + ': ' + r.stderr.strip()[:200]}))
except Exception:
    pass
"
